## Step 3: Create `src/services/order-service.ts`

**Imports required:**

```typescript
import { orders, products, getNextOrderId } from "../data.js";
import type { Order, OrderItem, CreateOrderInput } from "../types.js";
import { AppError } from "./errors.js";
```

**Type definitions:**

```typescript
export type EnrichedOrderItem = OrderItem & { productName: string };

export type EnrichedOrder = Omit<Order, "items"> & {
  items: EnrichedOrderItem[];
};

export type OrderListResult = {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
};
```

**`listOrders` function:**

```typescript
export interface OrderFilters {
  userId?: number;
  status?: string;
}

export function listOrders(filters: OrderFilters = {}): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }
  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}
```

**`getOrderById` function:**

```typescript
export function getOrderById(id: number): EnrichedOrder {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    throw new AppError("Order not found", 404);
  }

  const enrichedItems: EnrichedOrderItem[] = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return { ...item, productName: product?.name ?? "Unknown" };
  });

  return { ...order, items: enrichedItems };
}
```

**`createOrder` function:**

```typescript
export function createOrder(input: CreateOrderInput): Order {
  if (input.items.length === 0) {
    throw new AppError("Order must have at least one item", 400);
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      throw new AppError(`Product ${item.productId} not found`, 400);
    }
    if (item.quantity <= 0) {
      throw new AppError("Quantity must be positive", 400);
    }
    if (product.stock < item.quantity) {
      throw new AppError(`Insufficient stock for ${product.name}`, 400);
    }

    product.stock -= item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += product.price * item.quantity;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);
  return order;
}
```

**`updateOrderStatus` function:**

```typescript
const VALID_STATUSES = ["pending", "confirmed", "shipped", "delivered"] as const;

const TRANSITIONS: Record<string, string[]> = {
  pending: ["confirmed"],
  confirmed: ["shipped"],
  shipped: ["delivered"],
  delivered: [],
};

export function updateOrderStatus(id: number, status: string): Order {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    throw new AppError("Order not found", 404);
  }
  if (!VALID_STATUSES.includes(status as (typeof VALID_STATUSES)[number])) {
    throw new AppError(
      `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`,
      400
    );
  }
  if (!TRANSITIONS[order.status]?.includes(status)) {
    throw new AppError(
      `Cannot transition from ${order.status} to ${status}`,
      400
    );
  }

  order.status = status as Order["status"];
  return order;
}
```

The status value validation (`validStatuses.includes`) moves to the service because it is domain logic (the valid set of statuses is a business rule), not HTTP shape validation.

