import { Router } from "express";
import type { Response } from "express";
import type { CreateOrderInput } from "../types.js";
import { ValidationError } from "../errors.js";
import {
  getOrders,
  getOrderById,
  createOrder,
  updateOrderStatus,
} from "../services/order-service.js";

const router = Router();

function handleError(res: Response, err: unknown): void {
  if (err instanceof ValidationError) {
    res.status(400).json({ error: err.message });
  } else {
    res.status(500).json({ error: "Internal server error" });
  }
}

// GET /orders - list orders, optionally filter by userId or status
router.get("/orders", (req, res) => {
  const { userId, status } = req.query;
  const filters: { userId?: number; status?: string } = {};

  if (userId && typeof userId === "string") {
    const uid = parseInt(userId, 10);
    if (!isNaN(uid)) filters.userId = uid;
  }
  if (status && typeof status === "string") {
    filters.status = status;
  }

  res.json(getOrders(filters));
});

// GET /orders/:id
router.get("/orders/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const order = getOrderById(id);

    if (!order) {
      res.status(404).json({ error: "Order not found" });
      return;
    }

    res.json(order);
  } catch (err) {
    handleError(res, err);
  }
});

// POST /orders - create a new order
router.post("/orders", (req, res) => {
  try {
    const input = req.body as CreateOrderInput;

    if (!input.userId || !input.items || !Array.isArray(input.items)) {
      res.status(400).json({ error: "userId and items are required" });
      return;
    }

    const order = createOrder(input);
    res.status(201).json(order);
  } catch (err) {
    handleError(res, err);
  }
});

// PATCH /orders/:id/status - update order status
router.patch("/orders/:id/status", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { status } = req.body as { status: string };

    const order = updateOrderStatus(id, status);

    if (!order) {
      res.status(404).json({ error: "Order not found" });
      return;
    }

    res.json(order);
  } catch (err) {
    handleError(res, err);
  }
});

export { router as orderRouter };

