import { describe, it, expect, beforeEach } from "vitest";
import request from "supertest";
import { app } from "../src/app.js";
import { products } from "../src/data.js";

beforeEach(() => {
  // Reset products to original state before each test
  products.length = 0;
  products.push(
    { id: 1, name: "Laptop", price: 999.99, stock: 50, category: "electronics" },
    { id: 2, name: "Mouse", price: 29.99, stock: 200, category: "electronics" },
    { id: 3, name: "Keyboard", price: 79.99, stock: 150, category: "electronics" },
    { id: 4, name: "Desk", price: 299.99, stock: 30, category: "furniture" },
    { id: 5, name: "Chair", price: 199.99, stock: 40, category: "furniture" }
  );
});

describe("GET /products", () => {
  it("returns all products with summary stats", async () => {
    const res = await request(app).get("/products");
    expect(res.status).toBe(200);
    expect(res.body.products).toHaveLength(5);
    expect(res.body.summary).toMatchObject({
      count: 5,
    });
    expect(typeof res.body.summary.totalInventoryValue).toBe("number");
    expect(typeof res.body.summary.averagePrice).toBe("number");
  });

  it("filters by category", async () => {
    const res = await request(app).get("/products?category=electronics");
    expect(res.status).toBe(200);
    expect(res.body.products).toHaveLength(3);
    expect(res.body.summary.count).toBe(3);
    res.body.products.forEach((p: { category: string }) => {
      expect(p.category).toBe("electronics");
    });
  });

  it("filters by minPrice", async () => {
    const res = await request(app).get("/products?minPrice=200");
    expect(res.status).toBe(200);
    res.body.products.forEach((p: { price: number }) => {
      expect(p.price).toBeGreaterThanOrEqual(200);
    });
  });

  it("filters by maxPrice", async () => {
    const res = await request(app).get("/products?maxPrice=100");
    expect(res.status).toBe(200);
    res.body.products.forEach((p: { price: number }) => {
      expect(p.price).toBeLessThanOrEqual(100);
    });
  });

  it("filters by category and price range", async () => {
    const res = await request(app).get(
      "/products?category=electronics&maxPrice=100"
    );
    expect(res.status).toBe(200);
    expect(res.body.products).toHaveLength(2); // Mouse and Keyboard
  });
});

describe("GET /products/:id", () => {
  it("returns a product with computed fields", async () => {
    const res = await request(app).get("/products/1");
    expect(res.status).toBe(200);
    expect(res.body.id).toBe(1);
    expect(res.body.name).toBe("Laptop");
    expect(typeof res.body.isLowStock).toBe("boolean");
    expect(typeof res.body.inventoryValue).toBe("number");
  });

  it("returns isLowStock=false for well-stocked product", async () => {
    const res = await request(app).get("/products/1");
    expect(res.status).toBe(200);
    expect(res.body.isLowStock).toBe(false); // stock=50
  });

  it("returns 404 for non-existent product", async () => {
    const res = await request(app).get("/products/999");
    expect(res.status).toBe(404);
    expect(res.body.error).toBe("Product not found");
  });
});

describe("PATCH /products/:id/stock", () => {
  it("adjusts stock by positive adjustment", async () => {
    const res = await request(app)
      .patch("/products/1/stock")
      .send({ adjustment: 10 });
    expect(res.status).toBe(200);
    expect(res.body.stock).toBe(60);
  });

  it("adjusts stock by negative adjustment", async () => {
    const res = await request(app)
      .patch("/products/1/stock")
      .send({ adjustment: -5 });
    expect(res.status).toBe(200);
    expect(res.body.stock).toBe(45);
  });

  it("returns 400 when stock would go negative", async () => {
    const res = await request(app)
      .patch("/products/1/stock")
      .send({ adjustment: -999 });
    expect(res.status).toBe(400);
    expect(res.body.error).toBe("Insufficient stock");
  });

  it("returns 400 when adjustment is not a number", async () => {
    const res = await request(app)
      .patch("/products/1/stock")
      .send({ adjustment: "ten" });
    expect(res.status).toBe(400);
    expect(res.body.error).toBe("adjustment must be a number");
  });

  it("returns 404 for non-existent product", async () => {
    const res = await request(app)
      .patch("/products/999/stock")
      .send({ adjustment: 10 });
    expect(res.status).toBe(404);
    expect(res.body.error).toBe("Product not found");
  });
});

