import { describe, it, expect, beforeEach } from "vitest";
import request from "supertest";
import { app } from "../src/app.js";
import { orders, products } from "../src/data.js";

beforeEach(() => {
  // Reset products to original state
  products.length = 0;
  products.push(
    { id: 1, name: "Laptop", price: 999.99, stock: 50, category: "electronics" },
    { id: 2, name: "Mouse", price: 29.99, stock: 200, category: "electronics" },
    { id: 3, name: "Keyboard", price: 79.99, stock: 150, category: "electronics" },
    { id: 4, name: "Desk", price: 299.99, stock: 30, category: "furniture" },
    { id: 5, name: "Chair", price: 199.99, stock: 40, category: "furniture" }
  );

  // Reset orders to original state
  orders.length = 0;
  orders.push(
    {
      id: 1,
      userId: 1,
      items: [{ productId: 1, quantity: 1, price: 999.99 }],
      total: 999.99,
      status: "confirmed",
      createdAt: "2026-01-15T10:00:00Z",
    },
    {
      id: 2,
      userId: 2,
      items: [
        { productId: 2, quantity: 2, price: 29.99 },
        { productId: 3, quantity: 1, price: 79.99 },
      ],
      total: 139.97,
      status: "pending",
      createdAt: "2026-03-20T14:30:00Z",
    }
  );
});

describe("GET /orders", () => {
  it("returns all orders with summary", async () => {
    const res = await request(app).get("/orders");
    expect(res.status).toBe(200);
    expect(res.body.orders).toHaveLength(2);
    expect(res.body.summary.count).toBe(2);
    expect(typeof res.body.summary.totalRevenue).toBe("number");
  });

  it("filters by userId", async () => {
    const res = await request(app).get("/orders?userId=1");
    expect(res.status).toBe(200);
    expect(res.body.orders).toHaveLength(1);
    expect(res.body.orders[0].userId).toBe(1);
  });

  it("filters by status", async () => {
    const res = await request(app).get("/orders?status=pending");
    expect(res.status).toBe(200);
    expect(res.body.orders).toHaveLength(1);
    expect(res.body.orders[0].status).toBe("pending");
  });

  it("returns correct totalRevenue", async () => {
    const res = await request(app).get("/orders");
    expect(res.status).toBe(200);
    expect(res.body.summary.totalRevenue).toBeCloseTo(999.99 + 139.97, 2);
  });
});

describe("GET /orders/:id", () => {
  it("returns an order with enriched items", async () => {
    const res = await request(app).get("/orders/1");
    expect(res.status).toBe(200);
    expect(res.body.id).toBe(1);
    expect(res.body.items[0]).toHaveProperty("productName");
    expect(res.body.items[0].productName).toBe("Laptop");
  });

  it("returns enriched items for multi-item order", async () => {
    const res = await request(app).get("/orders/2");
    expect(res.status).toBe(200);
    expect(res.body.items).toHaveLength(2);
    expect(res.body.items[0].productName).toBe("Mouse");
    expect(res.body.items[1].productName).toBe("Keyboard");
  });

  it("returns 404 for non-existent order", async () => {
    const res = await request(app).get("/orders/999");
    expect(res.status).toBe(404);
    expect(res.body.error).toBe("Order not found");
  });
});

describe("POST /orders", () => {
  it("creates a new order and returns 201", async () => {
    const res = await request(app)
      .post("/orders")
      .send({ userId: 3, items: [{ productId: 2, quantity: 1 }] });
    expect(res.status).toBe(201);
    expect(res.body.userId).toBe(3);
    expect(res.body.status).toBe("pending");
    expect(typeof res.body.id).toBe("number");
    expect(typeof res.body.total).toBe("number");
  });

  it("deducts stock on order creation", async () => {
    const beforeStock = products.find((p) => p.id === 2)!.stock;
    await request(app)
      .post("/orders")
      .send({ userId: 3, items: [{ productId: 2, quantity: 5 }] });
    const afterStock = products.find((p) => p.id === 2)!.stock;
    expect(afterStock).toBe(beforeStock - 5);
  });

  it("returns 400 when userId is missing", async () => {
    const res = await request(app)
      .post("/orders")
      .send({ items: [{ productId: 1, quantity: 1 }] });
    expect(res.status).toBe(400);
    expect(res.body.error).toBe("userId and items are required");
  });

  it("returns 400 when items is empty", async () => {
    const res = await request(app)
      .post("/orders")
      .send({ userId: 1, items: [] });
    expect(res.status).toBe(400);
    expect(res.body.error).toBe("Order must have at least one item");
  });

  it("returns 400 for non-existent product", async () => {
    const res = await request(app)
      .post("/orders")
      .send({ userId: 1, items: [{ productId: 999, quantity: 1 }] });
    expect(res.status).toBe(400);
    expect(res.body.error).toBe("Product 999 not found");
  });

  it("returns 400 for insufficient stock", async () => {
    const res = await request(app)
      .post("/orders")
      .send({ userId: 1, items: [{ productId: 1, quantity: 9999 }] });
    expect(res.status).toBe(400);
    expect(res.body.error).toBe("Insufficient stock for Laptop");
  });

  it("returns 400 for non-positive quantity", async () => {
    const res = await request(app)
      .post("/orders")
      .send({ userId: 1, items: [{ productId: 1, quantity: 0 }] });
    expect(res.status).toBe(400);
    expect(res.body.error).toBe("Quantity must be positive");
  });
});

describe("PATCH /orders/:id/status", () => {
  it("updates order status along a valid transition", async () => {
    const res = await request(app)
      .patch("/orders/2/status")
      .send({ status: "confirmed" });
    expect(res.status).toBe(200);
    expect(res.body.status).toBe("confirmed");
  });

  it("returns 400 for invalid status value", async () => {
    const res = await request(app)
      .patch("/orders/2/status")
      .send({ status: "cancelled" });
    expect(res.status).toBe(400);
    expect(res.body.error).toMatch(/Invalid status/);
  });

  it("returns 400 for invalid status transition", async () => {
    const res = await request(app)
      .patch("/orders/2/status")
      .send({ status: "delivered" });
    expect(res.status).toBe(400);
    expect(res.body.error).toMatch(/Cannot transition from/);
  });

  it("returns 404 for non-existent order", async () => {
    const res = await request(app)
      .patch("/orders/999/status")
      .send({ status: "confirmed" });
    expect(res.status).toBe(404);
    expect(res.body.error).toBe("Order not found");
  });
});

